info.narration:
[
{การมีคนไว้ให้ไว้อาลัยหลังจากการตายถือเป็นพรอย่างหนึ่ง},
{ผู้ที่เหลืออยู่ไม่มีเวลาที่จะจดจำผู้ที่จากไป สิ่งที่พวกเขาทำได้คือเตรียมพร้อมสำหรับการตายครั้งต่อไป},
{$0 จ้องมองมาที่ #0 อย่างเงียบงัน}
]

[
{$0 กำลังฝัน ม่านได้ถูกดึงลงสู่ความใฝ่ฝันที่เกิดมาอย่างไร้ค่า แต่ก็ไม่มีบทสรุปที่ติดตามมา},
{โลงศพขนาดใหญ่ไม่เพียงพอที่จะทดแทนหลุมศพที่ยังไม่ได้ขุดอีกหลายร้อยหลุม},
{#0 ได้เห็นขบวนแห่ศพของผีเสื้อ},
{ปีกที่หนักอึ้งและกระพือเข้ามาใกล้ในแบบที่คุ้นเคยแต่ก็แปลกประหลาด}
]

[
{ไม่มีดอกไม้หรือต้นไม้ในสถานที่นี้ แล้วผีเสื้อทั้งหมดนี้มาจากไหนกัน?},
{พนักงานไม่สามารถกลับไปยังที่ที่พวกเขาจากมาได้ และไม่มีทางเลือกนอกจากต้องทำซ้ำวันเดิมๆ ไม่สิ้นสุด},
{ขบวนแห่ศพไม่เคยสิ้นสุด; #0 ยังคงไว้อาลัยอย่างสงบ},
{#0 คิดถึงจุดจบของชีวิต}
]

[
{การกลับไปยังที่ที่จากมาอย่างสมบูรณ์ตอนนี้กลายเป็นปาฏิหาริย์ที่จะไม่มีวันเกิดขึ้น},
{การตายอย่างสงบในช่วงเวลาที่รุ่งโรจน์ที่สุดถือเป็นพรที่ไม่คาดคิด},
{อันที่จริงแล้ว พนักงานส่วนใหญ่ที่เสียชีวิตที่นี่ต่างก็ต้องการมีชีวิตอยู่ให้นานที่สุดเท่าที่จะทำได้},
{บางคนคิดว่าความตายจะเป็นการเริ่มต้นใหม่; อย่างไรก็ตาม หลังจากความตายก็ไม่มีอะไรนอกจากความว่างเปล่า}
]

observe.desc:
			[
			{เมื่อคนตาย พวกเขาไปที่ไหนกัน?

พนักงานทุกคนที่ทำงานที่นี่ไปไหนกันหมด?}
			]

			[
			{- พวกเขาต้องกลับบ้านสิ ไปยังที่พักพิงที่มีครอบครัวและความอบอุ่นรออยู่

พนักงานไม่สามารถจากไปได้ เมื่อพวกเขาเข้าร่วมบริษัทแล้ว หนทางเดียวที่จะจากไปได้คือการลาออก

- ถ้าอย่างนั้นพนักงานที่ "ลาออก" เหล่านั้นก็คงกลับบ้านไปแล้ว โดยได้รับสิ่งที่พวกเขาต้องการและเต็มไปด้วยความหวัง}
			]
